function ajustarTelefone(raw) {
  if (!raw) return null;

  let t = raw.toString().replace(/\D/g, "");
  t = t.replace(/^0+/, "");

  if (t.length === 8) {
    t = "11" + "9" + t;
  } else if (t.length === 9) {
    t = "11" + t;
  } else if (t.length === 10) {
    t = t.replace(/^(\d{2})(\d{8})$/, "$19$2");
  } else if (t.length === 11) {
    t = "55" + t;
  } else if (t.length === 12) {
    t = t.slice(0, 4) + "9" + t.slice(4);
  } else if (t.length > 13) {
    t = t.slice(-13);
  }

  return t;
}

// ===== PROCESSAMENTO INDIVIDUAL =====
const item = $input.item.json;
const telefoneNormalizado = ajustarTelefone(item.property_contato);

return {
  json: {
    ...item,
    telefone_normalizado: telefoneNormalizado
  }
};

