  templateEscolhido = blocoTemplates.escolaflix;
} else if (produto.includes("mentoria")) {
  templateEscolhido = blocoTemplates.mentoria;
} else {
  templateEscolhido = blocoTemplates.mentoria; // fallback
}

// ==========================
// MONTAGEM DO BODY DO WHATSAPP
// ==========================
const body = {
  messaging_product: "whatsapp",
  to: String(entrada.telefoneAjustado || ""),
  type: "template",
  template: {
    name: templateEscolhido.name,
    language: { code: "pt_BR" },
    components: []
  }
};

// ==========================
// VARIÁVEIS DO TEMPLATE
// ==========================
const parameters = [];
if (templateEscolhido.vars >= 1) {
  parameters.push({ type: "text", text: String(entrada.var_1 || "") });
}
if (templateEscolhido.vars >= 2) {
  parameters.push({ type: "text", text: String(entrada.var_2 || "") });
}

body.template.components.push({
  type: "body",
  parameters
});

// ==========================
// TEXTO FINAL PARA HISTÓRICO
// ==========================
let textoFinal = templateEscolhido.text
  .replace("{{1}}", entrada.var_1 || "")
  .replace("{{2}}", entrada.var_2 || "");

// ==========================
// RETORNO FINAL FORMATADO
// ==========================
return [
